local LGpMgrBase = LxRequire("LApp.gameplay.base.LGpMgrBase")
---@class LMatchThreeGameManager: LGpMgrBase
local LMatchThreeGameManager = LxClass("LMatchThreeGameManager", LGpMgrBase)


local Touch           = LXImport(".Ctrl.LMatchThreeGameTouchCtrl")
local Pos             = LXImport(".Ctrl.LMatchThreeGamePosCtrl")
local Line            = LXImport(".Ctrl.LMatchThreeGameLineCtrl")
local Hud             = LXImport(".Ctrl.LMatchThreeGameHudCtrl")
local MainRole        = LXImport(".Ctrl.LMatchThreeGameMainRoleCtrl")
local Sword           = LXImport(".Ctrl.LMatchThreeGameSwordCtrl")
local EffsPool        = LXImport(".Ctrl.LMatchThreeGameEffsPoolCtrl")
local ObjsPool        = LXImport(".Ctrl.LMatchThreeGameObjsPoolCtrl")
local Objs            = LXImport(".Ctrl.LMatchThreeGameObjsCtrl")

-- 注意：有顺序要求
local CtrlList        = {
    { key = "Pos",      class = Pos },
    { key = "Line",     class = Line },
    { key = "Hud",      class = Hud },
    { key = "MainRole", class = MainRole },
    { key = "Sword",    class = Sword },
    { key = "Touch",    class = Touch },
    { key = "EffsPool", class = EffsPool },
    { key = "ObjsPool", class = ObjsPool },
    { key = "Objs",     class = Objs },
}

local Tweening        = DG.Tweening
local Ease            = Tweening.Ease
local Quaternion      = Quaternion
local Vector3         = Vector3

-- 消除时：移动一个节点的时间
local MoveOneNodeTime = 0.1

function LMatchThreeGameManager:LMatchThreeGameManager()
    -- LMatchThreeGameMap
    self._map = nil

    self._lock = false

    -- 开始游戏时间
    self._playGameStartTime = 0

    -- 控制类
    self._ctrlMaps = {}

    -- 特效列表
    self._effMap = {}

    self._inMap = true

    self:InitEvent()
end

function LMatchThreeGameManager:Destroy()
    self._inMap = nil

    self:DelayFuncClear()
    self:DeleteAllEff()
    self:DeleteCtrl()
    self:VibrateStop()

    if self._touchObjMoveSeq then
        self._touchObjMoveSeq:Kill(false)
        self._touchObjMoveSeq = nil
    end
    if self._startGameSeq then
        self._startGameSeq:Kill(false)
        self._startGameSeq = nil
    end

    LGpMgrBase.Destroy(self)
end

-- 删除所有特效
function LMatchThreeGameManager:DeleteAllEff()
    for name in pairs(self._effMap) do
        self:DeleteEff(name)
    end
    self._effMap = {}
end

-- 删除特效
function LMatchThreeGameManager:DeleteEff(name)
    local tab = self._effMap[name]
    if not tab then
        return
    end
    self._effMap[name] = nil
    if tab.effObj then
        CS.DestroyObject(tab.effObj)
        tab.effObj = nil
    end

    if tab.trans then
        CS.Destroy(tab.trans)
        tab.trans = nil
    end

    if tab.seq then
        tab.seq:Kill(false)
        tab.seq = nil
    end
end

-- 进入地图
function LMatchThreeGameManager:EnterMap(map)
    self._map = map
    self._inMap = true

    self:SetLock(true)
    self:InitCtrls()
    self:StartGame()
end

-- 退出地图
function LMatchThreeGameManager:ExitMap()
    self._inMap = nil

    self:DelayFuncClear()
    self:DeleteAllEff()
    self:DeleteCtrl()
    self:VibrateStop()

    if self._touchObjMoveSeq then
        self._touchObjMoveSeq:Kill(false)
        self._touchObjMoveSeq = nil
    end
    if self._startGameSeq then
        self._startGameSeq:Kill(false)
        self._startGameSeq = nil
    end
end

function LMatchThreeGameManager:InitEvent()
    self:EventRecv(EventNames.MATCH_THREE_GAME_OVER, function(...)
        if not self._inMap then
            return
        end
        self:OnGameOver(...)
    end)

    self:EventRecv(EventNames.ON_WND_FINISH, function(...) self:OnWndFinish(...) end)
end

function LMatchThreeGameManager:OnWndFinish(wndName)
    if wndName == "UIOrdinFightResult" then
        local touch = self:GetCtrl("Touch")
        if touch then
            touch:CancelTouch()
        end
    end
end

-- true:表示退出地图
function LMatchThreeGameManager:IsExit()
    return self._inMap == nil
end

-- 重新开始游戏
function LMatchThreeGameManager:OnRestartGame()
    self:ExitMap()
    self:EnterMap(self._map)
end

-- 初始化控制类
function LMatchThreeGameManager:InitCtrls()
    for _, tab in ipairs(CtrlList) do
        local ctrl = tab.class:New(self, self._map)
        ctrl:Init()
        self._ctrlMaps[tab.key] = ctrl
    end
end

-- 删除控制类
function LMatchThreeGameManager:DeleteCtrl()
    if self._ctrlMaps["Objs"] then
        self._ctrlMaps["Objs"]:Destroy()
        self._ctrlMaps["Objs"] = nil
    end
    for _, ctrl in pairs(self._ctrlMaps) do
        ctrl:Destroy()
    end
    self._ctrlMaps = {}
end

-- 获取控制类
function LMatchThreeGameManager:GetCtrl(name)
    return self._ctrlMaps[name]
end

-- 获取怪物数量
function LMatchThreeGameManager:GetMonsterNum()
    local objsCtrl = self:GetCtrl("Objs")
    if not objsCtrl then
        return nil
    end
    return objsCtrl:GetMonsterNum()
end

-- 设置锁定
function LMatchThreeGameManager:SetLock(bool)
    self._lock = bool

    if LOG_INFO_ENABLED then
        gModelMatchThreeGame:Log("设置锁定")
    end
end

-- true: 在锁定
function LMatchThreeGameManager:IsLock()
    return self._lock
end

-- 延迟函数
function LMatchThreeGameManager:DelayFunc(func, delayTime)
    self._delayFuncList = self._delayFuncList or {}
    local key = LxTimer.DelayTimeCall(func, delayTime)
    table.insert(self._delayFuncList, key)
end

-- 清除延迟函数
function LMatchThreeGameManager:DelayFuncClear()
    for _, key in ipairs(self._delayFuncList or {}) do
        LxTimer.DelayTimeStop(key)
    end
    self._delayFuncList = {}
end

-- 多次震动
function LMatchThreeGameManager:VibrateTimes(times)
    self:VibrateStop()
    times = times or 3
    self._vibrateTimer = LxTimer.LoopTimeCall(function() LNativeHelper.Vibrate() end, 0.2, true, times)
end

-- 停止震动
function LMatchThreeGameManager:VibrateStop()
    LxTimer.LoopTimeStop(self._vibrateTimer)
    self._vibrateTimer = nil
end

-- 开始游戏
function LMatchThreeGameManager:StartGame()
    if LOG_INFO_ENABLED then
        gModelMatchThreeGame:Log("开始游戏")
    end

    local initData = self._map:GetCameraInitData()
    local sceneCamera = gLGameScene:GetCurrentSceneCamera()
    local cameraTrans = sceneCamera.transform
    local offOrthographicSize = 1.5
    local offQuaternion = 30

    sceneCamera.orthographicSize = initData.orthographicSize - offOrthographicSize
    cameraTrans.rotation = Quaternion.Euler(offQuaternion, 0, 0)
    self._map:ResetCameraPos(0, Vector3(0, initData.pos.y - 2, 0))

    local seq = Tweening.DOTween.Sequence()

    local time = 1.2
    local tw1 = YXTween.TweenFloat(offQuaternion, 0, time * 0.8, function(ival)
        cameraTrans.rotation = Quaternion.Euler(ival, 0, 0)
    end)
    local tw2 = YXTween.TweenFloat(initData.orthographicSize - offOrthographicSize, initData.orthographicSize, time,
        function(ival)
            sceneCamera.orthographicSize = ival
        end)
    local tw3 = cameraTrans:DOMoveY(initData.pos.y, time * 0.9)

    seq:Insert(0, tw1)
    seq:Insert(0, tw2)
    seq:Insert(0, tw3)
    seq:OnComplete(function()
        self._startGameSeq = nil
        self:StartGameAniEnd()
    end)
    seq:Play()

    local objsCtrl = self:GetCtrl("Objs")
    objsCtrl:CreateNormalObj()
    objsCtrl:PlayNormalObjDropDown()

    self:SetLock(true)
    self._startGameAniCount = 2
    self._startGameSeq = seq
    FireEvent(EventNames.MATCH_THREE_GAME_MAP_INFO)
end

-- 开始游戏动画结束
function LMatchThreeGameManager:StartGameAniEnd()
    self._startGameAniCount = self._startGameAniCount - 1
    if self._startGameAniCount > 0 then
        return
    end

    self._startGameAniCount = nil
    self._playGameStartTime = os.time()

    self:GetCtrl("Pos"):InitNodeScreenPos()

    self:SetLock(false)

    if LOG_INFO_ENABLED then
        gModelMatchThreeGame:Log("开始游戏动画结束")
    end

    self._map:SendGuideReady()
end

-- 触摸结束
function LMatchThreeGameManager:TouchEnd(indexList)
    self._touchIndexList = indexList
    local count = #indexList
    local needCount = gModelMatchThreeGame:GetClearNodeNeedNum()
    self:GetCtrl("Objs"):ChangeObjState(indexList)
    if count < needCount then
        self:GetCtrl("Line"):SetLine({})
        self:GetCtrl("Sword"):Show(0, 0)
        return
    end

    self:SetLock(true)

    if gModelMatchThreeGame:IsMultiClear(count) then
        self:TouchObjMultiClear()
    else
        self:TouchObjStartMove()
    end

    gModelMatchThreeGame:ReduceActionTimes()
end

-- 获取消除的节点map; key:为index, value: 0 为普通，1为炸弹消除
function LMatchThreeGameManager:GetClearNodeList(indexList)
    local objsCtrl = self:GetCtrl("Objs")
    local posCtrl = self:GetCtrl("Pos")

    local listMap = {}
    local list = {}
    for i, v in ipairs(indexList) do
        list[i] = { [v] = 0 }
        listMap[v] = 0
    end

    for i, v in ipairs(indexList) do
        local roundIndexList = posCtrl:GetAroundIndex(v)
        for _, roundIndex in ipairs(roundIndexList) do
            local obj = objsCtrl:GetObj(roundIndex)
            if obj and not listMap[roundIndex] then
                if obj:IsBomb() and obj:GetHp() == 1 then
                    listMap[roundIndex] = 1
                    local oldMap = table.light_copy(listMap)
                    self:GetBombAroundMap(v, listMap)
                    local addMap = self:TableAddMap(oldMap, listMap)
                    addMap[roundIndex] = 1

                    for index, clearType in pairs(addMap) do
                        if objsCtrl:GetObj(index) then
                            list[i][index] = clearType
                        end
                    end
                else
                    listMap[roundIndex] = 0
                    list[i][roundIndex] = 0
                end
            end
        end
    end

    for i, tab in ipairs(list) do
        for index, clearType in pairs(tab) do
            if listMap[index] == 1 then
                tab[index] = 1
            end
        end
    end
    return list
end

-- 获取连接消除的节点map
function LMatchThreeGameManager:GetConnectClearMap(indexList)
    local posCtrl = self:GetCtrl("Pos")
    local connectClearMap = {}
    for i, v in ipairs(indexList) do
        local roundIndexList = posCtrl:GetAroundIndex(v)
        for _, roundIndex in ipairs(roundIndexList) do
            connectClearMap[roundIndex] = true
        end
    end
    return connectClearMap
end

-- 获取爆炸范围节点
function LMatchThreeGameManager:GetBombAroundMap(index, map)
    local posCtrl = self:GetCtrl("Pos")
    local objsCtrl = self:GetCtrl("Objs")

    local roundIndexList = posCtrl:GetAroundIndex(index)
    for j, roundIndex in ipairs(roundIndexList) do
        if posCtrl:IsValid(roundIndex) then
            if not map[roundIndex] then
                map[roundIndex] = 1
                local obj = objsCtrl:GetObj(roundIndex)
                if obj and obj:IsBomb() and obj:GetHp() == 1 then -- 此处多个炸弹，同时炸一个炸弹，也算一个炸弹（即多个炸弹同时炸，威力算一个）
                    self:GetBombAroundMap(roundIndex, map)
                end
            end
            map[roundIndex] = 1
        end
    end
end

-- 触摸对象多消
function LMatchThreeGameManager:TouchObjMultiClear()
    local posCtrl = self:GetCtrl("Pos")
    local objsCtrl = self:GetCtrl("Objs")
    local hudCtrl = self:GetCtrl("Hud")

    local indexList = self._touchIndexList
    local connectNum = #indexList
    local clearNodeList = self:GetClearNodeList(indexList)
    local connectClearMap = self:GetConnectClearMap(indexList)


    local total = 0
    local function finish()
        total = total - 1
        if total == 0 then
            self:TouchObjMultiClearEnd()
        end
    end

    local delayTime = 0
    for _, tab in ipairs(clearNodeList) do
        for index, clearType in pairs(tab) do
            local obj = objsCtrl:GetObj(index)

            local hp = obj:GetHp()
            obj:ChangeHp(connectNum, clearType, connectClearMap[index])
            local hp2 = obj:GetHp()
            local changeHp = hp2 - hp
            if obj:IsMonster() then
                local pos = posCtrl:GetPosByIndex(index):Clone()
                pos.x = pos.x + 0.5
                hudCtrl:ShowHud(pos, changeHp, false, delayTime)
            end
            
            if hp2 <= 0 then
                total = total + 1
                
                obj:PlayDead(nil, finish, delayTime)
            else
                self:DelayFunc(function()
                    obj:Refresh()
                end, delayTime)
            end
        end
        delayTime = delayTime + 0.15
    end

    self:GetCtrl("Line"):SetLine({})
    FireEvent(EventNames.MATCH_THREE_GAME_CONNECT, connectNum)
end

-- 触摸对象开始移动
function LMatchThreeGameManager:TouchObjStartMove()
    local DOTween = Tweening.DOTween
    local seq = DOTween.Sequence()

    local indexList = self._touchIndexList

    local objCtrl = self:GetCtrl("Objs")
    local posCtrl = self:GetCtrl("Pos")
    local lineCtrl = self:GetCtrl("Line")

    local obj = objCtrl:GetObj(indexList[1])
    local trans = obj:GetTransform()
    obj:Shake(false)
    lineCtrl:SetLine2(1, indexList)

    for i, v in ipairs(indexList) do
        local startK = i
        if i > 1 then
            local pos = posCtrl:GetPosByIndex(indexList[startK])
            local seq2 = DOTween.Sequence()

            local tw1 = trans:DOMove(pos, MoveOneNodeTime)
            seq2:Insert(0, tw1)

            seq2:InsertCallback(MoveOneNodeTime, function()
                lineCtrl:SetLine2(startK, indexList)
                -- LNativeHelper.Vibrate()
            end)

            seq2:InsertCallback(0, function()
                objCtrl:PlayDead(indexList[startK], MoveOneNodeTime * 0.7)
            end)

            seq:Append(seq2)
        end
    end

    seq:OnComplete(function()
        self._touchObjMoveSeq = nil
        self:TouchObjStartMoveEnd()
    end)

    seq:Play()
    self._touchObjMoveSeq = seq
end

-- 多消结束
function LMatchThreeGameManager:TouchObjMultiClearEnd()
    if LOG_INFO_ENABLED then
        gModelMatchThreeGame:Log("多消结束")
    end

    self:ClearEnd()
end

-- 触摸对象开始移动结束
function LMatchThreeGameManager:TouchObjStartMoveEnd()
    if LOG_INFO_ENABLED then
        gModelMatchThreeGame:Log("触摸对象开始移动结束")
    end

    local objsCtrl = self:GetCtrl("Objs")
    local posCtrl = self:GetCtrl("Pos")
    local hudCtrl = self:GetCtrl("Hud")

    local connectNum = #self._touchIndexList
    local firstIndex = self._touchIndexList[1]
    local lastIndex = self._touchIndexList[connectNum]
    objsCtrl:ChangeIndex(firstIndex, lastIndex)

    local total = 1
    local function finish()
        total = total - 1
        if total == 0 then
            self:ClearEnd()
        end
    end

    local clearNodeMap, clearLast = self:GetSwordClearNodeList(lastIndex)
    local connectClearMap = self:GetConnectClearMap({lastIndex})

    if clearLast then
        clearNodeMap[#clearNodeMap][lastIndex] = 1
    end

    local delayTime = 0
    for i, tab in ipairs(clearNodeMap) do
        delayTime = delayTime + 0.08
        for index, clearType in pairs(tab) do
            local obj = objsCtrl:GetObj(index)
            if obj then
                local hp = obj:GetHp()
                obj:ChangeHp(connectNum, clearType, connectClearMap[index])
                local hp2 = obj:GetHp()
                if obj:IsMonster() then
                    local changeHp = hp2 - hp
                    local pos = posCtrl:GetPosByIndex(index):Clone()
                    pos.x = pos.x + 0.5
                    hudCtrl:ShowHud(pos, changeHp)
                end

                if hp2 <= 0 then
                    total = total + 1

                    obj:PlayDead(nil, finish, delayTime)
                else
                    obj:Refresh()
                end
            end
        end
        -- if i == 4 then
        --     self:DelayFunc(function()
        --         LNativeHelper.Vibrate()
        --     end, delayTime)
        -- end
    end

    self:GetCtrl("Sword"):StartSword(function()
        local obj = objsCtrl:GetObj(lastIndex)
        if obj and not clearLast then
            obj:Refresh()
        end
        self:ClearEnd()
    end)

    FireEvent(EventNames.MATCH_THREE_GAME_CONNECT, connectNum)
end

-- 获取挥剑消除的节点
-- 节点有排序：
-- 1 2 3
-- 4 5 6
-- 7 8 9
-- 排序成：3 6 9 8 7 4 1 2
function LMatchThreeGameManager:GetSwordClearNodeList(centerIndex)
    local posCtrl = self:GetCtrl("Pos")
    local objsCtrl = self:GetCtrl("Objs")
    local col = posCtrl:GetCol()

    local sortList = {}
    sortList[1] = centerIndex + 1 - col
    sortList[2] = centerIndex + 1
    sortList[3] = centerIndex + 1 + col
    sortList[4] = centerIndex + col
    sortList[5] = centerIndex + col - 1
    sortList[6] = centerIndex - 1
    sortList[7] = centerIndex - col - 1
    sortList[8] = centerIndex - col


    local list = posCtrl:GetAroundIndex(centerIndex)
    local validMap = {}
    for i, v in ipairs(list) do
        if posCtrl:IsValid(v) then
            validMap[v] = true
        end
    end


    local listMap = {}
    local list = {}
    for i, v in ipairs(sortList) do
        list[i] = {}
        local obj = objsCtrl:GetObj(v)
        if obj and validMap[v] then
            if obj:IsBomb() and obj:GetHp() == 1 then
                listMap[v] = 1
                local oldMap = table.light_copy(listMap)
                self:GetBombAroundMap(v, listMap)
                local addMap = self:TableAddMap(oldMap, listMap)
                addMap[v] = 1
                list[i] = addMap

                for index, clearType in pairs(addMap) do
                    listMap[index] = clearType
                end
            else
                if not listMap[v] then
                    list[i] = { [v] = 0 }
                    listMap[v] = 0
                end
            end
        end
    end

    local clearLast = false
    for i, tab in ipairs(list) do
        for index, clearType in pairs(tab) do
            if listMap[index] == 1 then
                tab[index] = 1
            end
            if index == centerIndex and tab[index] == 1 then
                clearLast = true
                tab[index] = nil
            end
        end
    end
    return list, clearLast
end

-- 新增的map
function LMatchThreeGameManager:TableAddMap(oldMap, newMap)
    local addMap = {}
    for k, v in pairs(newMap) do
        if not oldMap[k] then
            addMap[k] = v
        end
    end
    return addMap
end

-- 清除结束
function LMatchThreeGameManager:ClearEnd()
    if LOG_INFO_ENABLED then
        gModelMatchThreeGame:Log("清除结束")
    end

    if self:CheckResult() then
        return
    end

    local objsCtrl = self:GetCtrl("Objs")
    objsCtrl:CreateNormalObj()
    objsCtrl:PlayNormalObjDropDown()

    self._needMonsterMove = true

    FireEvent(EventNames.MATCH_THREE_GAME_MAP_INFO)
end

-- 播正常对象下落完成
function LMatchThreeGameManager:OnPlayNormalObjDropDownFinish()
    if LOG_INFO_ENABLED then
        gModelMatchThreeGame:Log("播正常对象下落完成")
    end

    if self._startGameAniCount then
        self:StartGameAniEnd()
        return
    end

    if self._needMonsterMove then
        self._needMonsterMove = nil
        self:GetCtrl("Objs"):PlayMonsterMove()
        return
    end
    self:SetLock(false)
end

-- 怪物移动结束
function LMatchThreeGameManager:OnPlayMonsterMoveFinish()
    if LOG_INFO_ENABLED then
        gModelMatchThreeGame:Log("怪物移动结束")
    end

    if self:CheckResult() then
        return
    end

    local objsCtrl = self:GetCtrl("Objs")
    objsCtrl:CreateNormalObj()
    objsCtrl:PlayNormalObjDropDown()
end

-- 跳到某个坐标（世界坐标）
function LMatchThreeGameManager:Jump(trans, fromPos, toPos, duration, endFunc)
    trans.position = fromPos

    duration = duration or 0.5
    local tw1 = trans:DOJump(toPos, 0.1, 1, duration)
    local tw2 = trans:DOScale(1, duration)

    local seq = Tweening.DOTween.Sequence()
    seq:Insert(0, tw1)
    seq:Insert(0, tw2)

    seq:OnComplete(function()
        if endFunc then
            endFunc()
        end
    end)
    seq:Play()
    return seq
end

-- 使用道具结束
function LMatchThreeGameManager:UseItemEnd()
    if LOG_INFO_ENABLED then
        gModelMatchThreeGame:Log("使用道具结束")
    end

    self._needMonsterMove = true

    local objsCtrl = self:GetCtrl("Objs")
    objsCtrl:CreateNormalObj()
    objsCtrl:PlayNormalObjDropDown()

    FireEvent(EventNames.MATCH_THREE_GAME_MAP_INFO)
end

-- true: 表示准备使用道具
function LMatchThreeGameManager:IsReadyUseItem()
    return self._useItemType ~= nil
end

-- 设置准备使用道具：1: 使用锤子，2: 使用炸弹, nil表示不准备使用道具
function LMatchThreeGameManager:SetReadyUseItem(useType)
    self._useItemType = useType
end

-- 使用道具到某个下标
function LMatchThreeGameManager:UseItemToIndex(index)
    self._useItemToIndex = index

    self:SetLock(true)
    local barrierId = gModelMatchThreeGame:GetRefId()
    gModelMatchThreeGame:ConnectionMiniGameUseItemReq({ barrierId = barrierId, key = self._useItemType })
end

-- 预加载使用物品特效
function LMatchThreeGameManager:ReloadUseItemEff(key)
    local effsPool = self:GetCtrl("EffsPool")
    if key == 1 then
        effsPool:LoadEffObj(gModelMatchThreeGame.EffRes.Hammer)
    elseif key == 2 then
        effsPool:LoadEffObj(gModelMatchThreeGame.EffRes.BombFly)
        effsPool:LoadEffObj(gModelMatchThreeGame.EffRes.BombHit)
    elseif key == 3 then
        effsPool:LoadEffObj(gModelMatchThreeGame.EffRes.SuperBomb)
    end
end

-- region 使用锤子 ----------------------------------------------------

-- 播放使用锤子动画
function LMatchThreeGameManager:PlayUseHammer()
    self:SetReadyUseItem(nil)
    FireEvent(EventNames.MATCH_THREE_GAME_CANCEL_USE_ITEM)

    local toIndex = self._useItemToIndex
    local obj = self:GetCtrl("Objs"):GetObj(toIndex)
    if obj:IsBurrow() or obj:IsBomb() then
        self:SetLock(false)
        return
    end

    local effsPool = self:GetCtrl("EffsPool")
    local posCtrl = self:GetCtrl("Pos")
    local parent = effsPool:GetNodeParent()


    local toPos = posCtrl:GetPosByIndex(toIndex)

    self:DeleteEff("hammer")
    local function LoadEnd(originalObj)
        if not self._inMap then
            return
        end

        local obj = LxUnity.InstantObject(originalObj)
        local trans = obj.transform
        trans:SetParent(parent, false)
        trans.position = toPos
        CS.ShowObject(trans, true)

        local tab = {}
        tab.effObj = obj

        self._effMap["hammer"] = tab

        self:PlayObjWhenUseHammer()

        gLGameAudio:PlaySoundByRefId(365)
        self:VibrateTimes(1)
    end

    effsPool:LoadEffObj(gModelMatchThreeGame.EffRes.Hammer, LoadEnd)
end

-- 刷新对象，当使用锤子时
function LMatchThreeGameManager:PlayObjWhenUseHammer()
    local objsCtrl = self:GetCtrl("Objs")
    local index = self._useItemToIndex
    local obj = objsCtrl:DeleteObj(index)
    if obj then
        obj:SetHp(0)
        obj:PlayDead(nil, function() self:PlayObjWhenUseHammerFinish() end)
    else
        self:PlayObjWhenUseHammerFinish()
    end
end

-- 使用锤子结束
function LMatchThreeGameManager:PlayObjWhenUseHammerFinish()
    self:DelayFunc(function() self:UseItemEnd() end, 0.3)
end

-- endregion 使用锤子 ----------------------------------------------------

-- region 使用炸弹 ----------------------------------------------------

-- 播放炸弹 飞行动画
function LMatchThreeGameManager:PlayBombFly(fromPos)
    local effsPool = self:GetCtrl("EffsPool")
    local posCtrl = self:GetCtrl("Pos")
    local parent = effsPool:GetNodeParent()

    local toIndex = self._useItemToIndex
    local toPos = posCtrl:GetPosByIndex(toIndex)


    local function LoadEnd(originalObj)
        if not self._inMap then
            return
        end

        local obj = LxUnity.InstantObject(originalObj)
        local trans = obj.transform
        trans:SetParent(parent, false)
        trans.position = fromPos
        CS.ShowObject(trans, true)

        trans.localEulerAngles  = Vector3(0, 0, 90)
        -- trans:LookAt(toPos)
        local tab               = {}
        local seq               = self:Jump(trans, trans.position, toPos, 0.5,
            function() self:PlayBombFlyFinish(toPos) end)
        tab.trans               = trans
        tab.seq                 = seq
        self._effMap["bombFly"] = tab
        tab.effObj              = obj
    end

    effsPool:LoadEffObj(gModelMatchThreeGame.EffRes.BombFly, LoadEnd)
end

-- 播放炸弹 飞行动画 结束
function LMatchThreeGameManager:PlayBombFlyFinish(toPos)
    local tab = self._effMap["bombFly"]
    if tab.trans then
        CS.Destroy(tab.trans)
        tab.trans = nil
    end
    if tab.seq then
        tab.seq:Kill()
        tab.seq = nil
    end

    self:SetReadyUseItem(nil)
    FireEvent(EventNames.MATCH_THREE_GAME_CANCEL_USE_ITEM)

    self:DeleteEff("bombHit")

    local effsPool = self:GetCtrl("EffsPool")
    local parent = effsPool:GetNodeParent()

    local function LoadEnd(originalObj)
        if not self._inMap then
            return
        end

        local obj = LxUnity.InstantObject(originalObj)
        local trans = obj.transform
        trans:SetParent(parent, false)
        trans.position = toPos
        CS.ShowObject(trans, true)

        local tab = {}
        tab.effObj = obj

        self._effMap["bombHit"] = tab

        self:PlayObjWhenUseBomb()

        gLGameAudio:PlaySoundByRefId(366)
        self:VibrateTimes(2)
    end

    effsPool:LoadEffObj(gModelMatchThreeGame.EffRes.BombHit, LoadEnd)
end

-- 刷新对象，当使用炸弹时
function LMatchThreeGameManager:PlayObjWhenUseBomb()
    if self:IsExit() then
        return
    end

    local total = 0
    local function finish()
        total = total - 1

        if total == 0 then
            self:PlayObjWhenUseBombFinish()
        end
    end

    local useBombIndex = self._useItemToIndex
    local posCtrl = self:GetCtrl("Pos")
    local objsCtrl = self:GetCtrl("Objs")
    local indexList = posCtrl:GetAroundIndex(useBombIndex)
    table.insert(indexList, useBombIndex)
    for i, index in ipairs(indexList) do
        local obj = objsCtrl:GetObj(index)
        if obj and not obj:IsBurrow() then
            local hp = obj:GetHp()
            if obj:IsBox() then
                obj:SetHp(hp - 1)
            else
                obj:SetHp(0)
            end
            hp = obj:GetHp()
            if hp <= 0 then
                total = total + 1
                local obj2 = objsCtrl:DeleteObj(index)
                obj2:PlayDead(nil, finish)
            else
                obj:Refresh()
            end
        end
    end
    if total == 0 then
        self:PlayObjWhenUseBombFinish()
    end
end

-- 播放炸弹动画 结束
function LMatchThreeGameManager:PlayObjWhenUseBombFinish()
    self:DeleteEff("bombFly")
    self:UseItemEnd()
end

-- endregion 使用炸弹 ----------------------------------------------------


-- region 使用全屏炸弹 ----------------------------------------------------

-- 使用全屏炸弹
function LMatchThreeGameManager:PlaySuperBomb(originalTrans)
    local obj = LxUnity.InstantObject(originalTrans.gameObject)
    local trans = obj.transform
    trans:SetParent(originalTrans.parent, false)

    local toPos               = Vector3(0, 0, 0)
    local tab                 = {}
    local seq                 = self:Jump(trans, trans.position, toPos, 0.5,
        function() self:PlaySuperBombJumpFinish(toPos) end)
    tab.trans                 = trans
    tab.seq                   = seq
    self._effMap["superBomb"] = tab
end

-- 使用全屏炸弹 跳动画完成
function LMatchThreeGameManager:PlaySuperBombJumpFinish(pos)
    local tab = self._effMap["superBomb"]
    if tab.trans then
        CS.Destroy(tab.trans)
        tab.trans = nil
    end
    if tab.seq then
        tab.seq:Kill()
        tab.seq = nil
    end

    local effsPool = self:GetCtrl("EffsPool")
    local parent = effsPool:GetNodeParent()

    local function LoadEnd(originalObj)
        if not self._inMap then
            return
        end

        local obj = LxUnity.InstantObject(originalObj)
        local trans1 = obj.transform
        trans1:SetParent(parent, false)
        trans1.position = pos
        CS.ShowObject(trans1, true)

        tab.effObj = obj

        self:PlayObjWhenUseSuperBomb()

        gLGameAudio:PlaySoundByRefId(367)

        self:VibrateTimes(4)
    end

    effsPool:LoadEffObj(gModelMatchThreeGame.EffRes.SuperBomb, LoadEnd)
end

-- 播放全屏炸弹, 刷新对象
function LMatchThreeGameManager:PlayObjWhenUseSuperBomb()
    if self:IsExit() then
        return
    end

    local total = 0
    local function finish()
        total = total - 1

        if total == 0 then
            self:PlayObjWhenUseSuperBombFinish()
        end
    end


    local objsCtrl = self:GetCtrl("Objs")
    local objMap = objsCtrl:GetAllObjs()
    for index, obj in pairs(objMap) do
        if not obj:IsBurrow() then
            local hp = obj:GetHp()
            if obj:IsBox() then
                obj:SetHp(hp - 1)
            else
                obj:SetHp(0)
            end
            hp = obj:GetHp()
            if hp <= 0 then
                objMap[index] = nil
                total = total + 1
                obj:PlayDead(nil, finish)
            else
                obj:Refresh()
            end
        end
    end
end

-- 播放全屏炸弹动画 结束
function LMatchThreeGameManager:PlayObjWhenUseSuperBombFinish()
    self:DeleteEff("superBomb")
    self:UseItemEnd()
end

-- endregion 使用全屏炸弹 ----------------------------------------------------

-- 检查结果,true: 游戏结束
function LMatchThreeGameManager:CheckResult()
    local actionTimes = gModelMatchThreeGame:GetActionTimes()
    local monsterNum = self:GetMonsterNum()
    local mainRole = self:GetCtrl("MainRole")
    local curHp = mainRole:GetHp()
    if actionTimes <= 0 then
        if monsterNum <= 0 and actionTimes == 0 and curHp > 0 then
            FireEvent(EventNames.MATCH_THREE_GAME_OVER, { isWin = true })
            return true
        end
        
        FireEvent(EventNames.MATCH_THREE_GAME_OVER, { isWin = false })
        return true
    end

    if monsterNum <= 0 then
        FireEvent(EventNames.MATCH_THREE_GAME_OVER, { isWin = curHp > 0  })
        return true
    end

    return false
end

-- 游戏结束
function LMatchThreeGameManager:OnGameOver(param)
    local data = {}
    data.result = param.isWin and 1 or 2
    data.barrierId = gModelMatchThreeGame:GetRefId()
    data.useTime = os.time() - self._playGameStartTime

    gModelMatchThreeGame:ConnectionMiniGamePassReq(data)
end

return LMatchThreeGameManager
